RES = '1,3,3,1,60,3', LA = 1, CFS = 'Envelope Name~' + Contract.Clinician_First_Name__c + ' ' + Contract.Clinician_Last_Name__c + ' - Term Sheet' + '~1~1,Document Type~Term Sheet~1~1' ] )}
